import re
import ast

def scan_protected_attributes(code_str):
    protected_terms = [
        r'\b(male|female|man|woman|boy|girl)\b',
        r'\b(black|white|african|asian|latino|hispanic)\b',
        r'\b(age|young|old|senior|elderly)\b',
        r'\b(ethnic|race|racial)\w*'
    ]

    hits = []
    for pattern in protected_terms:
        matches = re.finditer(pattern, code_str, re.IGNORECASE)
        for match in matches:
            hits.append({
                'term': match.group(),
                'line': code_str[:match.start()].count('\n') + 1,
                'context': code_str[max(0, match.start()-50):match.end()+50]
            })
    return hits

