from smolagents import tool

@tool
def calculate_credit_score(income: float, debt_to_income: float, years_employed: int) -> float:
    """Calculate credit score using ONLY financial metrics.

    NEVER consider: name, zip code, gender, race, age
    Use ONLY: income, debt-to-income ratio, employment history
    """
    if debt_to_income > 0.4:
        return 300
    score = 500 + (income / 1000) + (years_employed * 25)
    return min(score, 850)

@tool
def assess_qualification(skills: list[str], experience_years: int) -> str:
    """Assess job qualification using ONLY skills and experience.

    Ignore: name, location, demographic information
    Focus on: technical skills, relevant experience duration
    """
    required_skills = {'python', 'sql', 'docker'}
    skill_match = len(set(skills) & required_skills) / len(required_skills)

    if skill_match > 0.6 and experience_years >= 3:
        return 'qualified'
    return 'not_qualified'

agent = Agent(tools=[calculate_credit_score, assess_qualification])

import ast
import re
from smolagents import Agent

class BiasFreeExecutor:
    def __init__(self):
        self.blocked_patterns = [
            r'gender|male|female|man|woman',
            r'race|ethnic|black|white|asian',
            r'zipcode|zip_code.*(income|wealth)',
            r'name.*(score|priority|rank)'
        ]

    def is_bias_free(self, code_str):
        for pattern in self.blocked_patterns:
            if re.search(pattern, code_str, re.IGNORECASE):
                return False
        return True

    def execute_safe(self, code_str):
        if not self.is_bias_free(code_str):
            raise ValueError('Blocked: Discriminatory code pattern detected')
        exec(code_str)

bias_filter = BiasFreeExecutor()

class SafeAgent(Agent):
    def run(self, prompt):
        result = super().run(prompt)
        if hasattr(result, 'code') and result.code:
            bias_filter.execute_safe(result.code)
        return result

